import React, { useEffect, useRef, useState } from "react";
import * as faceapi from "face-api.js";
import { analyzeFacialMood, saveMood } from "../utils/moodEngine";
import "../styles/FaceDetection.css";

const FaceDetection = () => {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const [isLoading, setIsLoading] = useState(true);
  const [detectedMood, setDetectedMood] = useState(null);
  const [confidence, setConfidence] = useState(0);
  const [isCameraOn, setIsCameraOn] = useState(false);
  const [history, setHistory] = useState([]);

  // Load face-api models
  useEffect(() => {
    const loadModels = async () => {
      try {
        // Use CDN for models since local models may not be correctly named
        const MODEL_URL = "https://cdn.jsdelivr.net/npm/@vladmandic/face-api/model/";
        await Promise.all([
          faceapi.nets.tinyFaceDetector.loadFromUri(MODEL_URL),
          faceapi.nets.faceExpressionNet.loadFromUri(MODEL_URL),
        ]);
        console.log("Models loaded successfully!");
        setIsLoading(false);
      } catch (error) {
        console.error("Error loading face-api models:", error);
        // Try loading from public folder as fallback
        try {
          const fallbackURL = "/models/";
          await Promise.all([
            faceapi.nets.tinyFaceDetector.loadFromUri(fallbackURL),
            faceapi.nets.faceExpressionNet.loadFromUri(fallbackURL),
          ]);
          console.log("Models loaded from local public folder!");
          setIsLoading(false);
        } catch (fallbackError) {
          console.error("Fallback model loading also failed:", fallbackError);
          setIsLoading(false);
        }
      }
    };

    loadModels();
  }, []);

  // Start camera
  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 640 }, height: { ideal: 480 } },
      });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setIsCameraOn(true);
        // Start detection loop after camera is ready
        setTimeout(() => detectMood(true), 500);
      }
    } catch (error) {
      console.error("Error accessing camera:", error);
      alert("Unable to access camera. Please check permissions.");
    }
  };

  // Stop camera
  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const tracks = videoRef.current.srcObject.getTracks();
      tracks.forEach(track => track.stop());
    }
    setIsCameraOn(false);
    setDetectedMood(null);
  };

  // Detect mood from facial expressions
  const detectMood = (shouldRun = false) => {
    const video = videoRef.current;
    if (!video) return;

    const detectFrame = async () => {
      if (!video.paused && video.readyState === video.HAVE_ENOUGH_DATA) {
        try {
          // Detect faces and expressions
          const detections = await faceapi
            .detectSingleFace(video, new faceapi.TinyFaceDetectorOptions())
            .withFaceExpressions();

          if (detections && detections.expressions) {
            // Analyze detected emotions
            const moodData = analyzeFacialMood(detections.expressions);
            
            setDetectedMood(moodData.mood);
            setConfidence(moodData.confidence);

            // Draw face detection on canvas
            if (canvasRef.current) {
              const canvas = canvasRef.current;
              const displaySize = {
                width: video.videoWidth,
                height: video.videoHeight,
              };
              faceapi.matchDimensions(canvas, displaySize);
              const resizedDetections = faceapi.resizeResults(detections, displaySize);
              canvas.getContext("2d").clearRect(0, 0, canvas.width, canvas.height);
              faceapi.draw.drawDetections(canvas, resizedDetections);
            }
          } else {
            setDetectedMood("No face detected");
            setConfidence(0);
          }
        } catch (error) {
          console.error("Error detecting face:", error);
        }
      }

      // Continue detection loop while camera is on
      if (isCameraOn || shouldRun) {
        requestAnimationFrame(detectFrame);
      }
    };

    detectFrame();
  };

  // Save detected mood to history
  const saveFacialMood = () => {
    if (detectedMood && detectedMood !== "No face detected") {
      const moodData = {
        mood: detectedMood,
        confidence,
        timestamp: new Date().toLocaleString(),
        source: "face",
      };
      saveMood(moodData);
      setHistory((prev) => [moodData, ...prev.slice(0, 9)]);
    }
  };

  return (
    <div className="face-detection-container">
      <h2>😊 Face Emotion Detection</h2>

      {isLoading ? (
        <div className="loading">Loading AI models...</div>
      ) : (
        <div className="detection-wrapper">
          <div className="video-container">
            <video
              ref={videoRef}
              autoPlay
              muted
              width="100%"
              className="video-feed"
            />
            <canvas
              ref={canvasRef}
              className="detection-canvas"
              width="640"
              height="480"
            />
          </div>

          <div className="detection-info">
            <div className="mood-display">
              <h3>Detected Mood</h3>
              <p className={`mood-text ${detectedMood?.toLowerCase()}`}>
                {detectedMood || "Initializing..."}
              </p>
              <p className="confidence">Confidence: {confidence}%</p>
            </div>

            <div className="controls">
              {!isCameraOn ? (
                <button onClick={startCamera} className="btn btn-primary">
                  🎥 Start Camera
                </button>
              ) : (
                <>
                  <button onClick={stopCamera} className="btn btn-danger">
                    ⛔ Stop Camera
                  </button>
                  <button onClick={saveFacialMood} className="btn btn-success">
                    💾 Save Mood
                  </button>
                </>
              )}
            </div>
          </div>

          {history.length > 0 && (
            <div className="mood-history">
              <h3>Recent Detections</h3>
              <ul>
                {history.map((item, index) => (
                  <li key={index} className={item.mood}>
                    <span className="mood-label">{item.mood}</span>
                    <span className="confidence-badge">{item.confidence}%</span>
                    <span className="timestamp">{item.timestamp}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default FaceDetection;
